use std::arch::x86_64::*;

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0;

    // We assume length is 128 as stated in the requirements.
    if a.len() == 128 && b.len() == 128 {
        unsafe {
            let mut sum_vec = _mm512_setzero_ps();
            for i in (0..128).step_by(16) {
                let va = _mm512_loadu_ps(a.as_ptr().add(i));
                let vb = _mm512_loadu_ps(b.as_ptr().add(i));
                let diff = _mm512_sub_ps(va, vb);
                let sq = _mm512_mul_ps(diff, diff);
                sum_vec = _mm512_add_ps(sum_vec, sq);
            }
            sum = _mm512_reduce_add_ps(sum_vec) as f64;
        }
    } else {
        for i in 0..a.len() {
            let diff = a[i] - b[i];
            sum += (diff * diff) as f64;
        }
    }

    sum
}

use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;
use ordered_float::OrderedFloat;

pub struct VectorDB {
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl Default for VectorDB {
    fn default() -> Self {
        Self::new()
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.vectors.write().unwrap();
        guard.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut guard = self.vectors.write().unwrap();
        guard.extend(vectors);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let guard = self.vectors.read().unwrap();
        let mut results: Vec<_> = guard.par_iter()
            .map(|(id, v)| {
                let dist = l2_distance(v, vector);
                (*id, dist)
            })
            .collect();

        results.sort_unstable_by_key(|&(_, dist)| OrderedFloat(dist));

        results.into_iter()
            .take(top_k as usize)
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}

