}

impl Default for VectorDB {
    fn default() -> Self {
        Self::new()
    }
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
            ids: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, mut vector: Vec<f32>) {
        let mut vecs_guard = self.vectors.write().unwrap();
        let mut ids_guard = self.ids.write().unwrap();
        vecs_guard.append(&mut vector);
        ids_guard.push(id);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut vecs_guard = self.vectors.write().unwrap();
        let mut ids_guard = self.ids.write().unwrap();
        for (id, mut v) in vectors {
            vecs_guard.append(&mut v);
            ids_guard.push(id);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vecs_guard = self.vectors.read().unwrap();
        let ids_guard = self.ids.read().unwrap();
        let dim = 128;
        let num_vectors = ids_guard.len();

        let mut results = Vec::with_capacity(num_vectors);
        for i in 0..num_vectors {
            let start = i * dim;
            let end = start + dim;
            let v = &vecs_guard[start..end];
            let dist = l2_distance(v, vector);
            results.push((ids_guard[i], dist));
        }

        results.sort_unstable_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        results.into_iter()
            .take(top_k as usize)
            .map(|(id, distance)| SearchResult { id, distance })
            .collect()
    }
}

use std::arch::x86_64::*;

// #[target_feature(enable = "avx512f")] // Removed so compiler doesn't complain if not unconditionally supported at compile-time, we set native
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    // Both are 128 long
    if a.len() == 128 && b.len() == 128 {
        unsafe { l2_distance_avx512(a, b) }
    } else {
        l2_distance_fallback(a, b)
    }
}

// We will assume the CPU has AVX-512 as stated.
#[target_feature(enable = "avx512f", enable = "avx512vl", enable = "avx512dq")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum_vec = _mm512_setzero_ps();
    let mut sum_vec2 = _mm512_setzero_ps();
    let mut sum_vec3 = _mm512_setzero_ps();
    let mut sum_vec4 = _mm512_setzero_ps();

    let ap = a.as_ptr();
    let bp = b.as_ptr();

    // 128 floats = 8 zmm registers
    for i in (0..128).step_by(64) {
        let va1 = _mm512_loadu_ps(ap.add(i));
        let vb1 = _mm512_loadu_ps(bp.add(i));
        let diff1 = _mm512_sub_ps(va1, vb1);
        sum_vec = _mm512_fmadd_ps(diff1, diff1, sum_vec);

        let va2 = _mm512_loadu_ps(ap.add(i + 16));
        let vb2 = _mm512_loadu_ps(bp.add(i + 16));
        let diff2 = _mm512_sub_ps(va2, vb2);
        sum_vec2 = _mm512_fmadd_ps(diff2, diff2, sum_vec2);

        let va3 = _mm512_loadu_ps(ap.add(i + 32));
        let vb3 = _mm512_loadu_ps(bp.add(i + 32));
        let diff3 = _mm512_sub_ps(va3, vb3);
        sum_vec3 = _mm512_fmadd_ps(diff3, diff3, sum_vec3);

        let va4 = _mm512_loadu_ps(ap.add(i + 48));
        let vb4 = _mm512_loadu_ps(bp.add(i + 48));
        let diff4 = _mm512_sub_ps(va4, vb4);
        sum_vec4 = _mm512_fmadd_ps(diff4, diff4, sum_vec4);
    }

    let sum12 = _mm512_add_ps(sum_vec, sum_vec2);
    let sum34 = _mm512_add_ps(sum_vec3, sum_vec4);
    let sum = _mm512_add_ps(sum12, sum34);

    _mm512_reduce_add_ps(sum) as f64
}

fn l2_distance_fallback(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0;
    for i in 0..a.len() {
        let diff = a[i] - b[i];
        sum += (diff * diff) as f64;
    }
    sum
}

